noncompliant:
struct Point {
    int x, y;
};

struct Person {
    std::string name;
    int age;
};

void function() {
    // Noncompliant - using parentheses for aggregate initialization in non-generic code
    Point p(10, 20);
    Person person(std::string("John"), 25);

    // Noncompliant - array initialization with parentheses
    int arr[3](1, 2, 3);  // This won't compile, but conceptually wrong approach
}

compliant:
struct Point {
    int x, y;
};

struct Person {
    std::string name;
    int age;
};

void function() {
    // Compliant - using braces for aggregate initialization
    Point p{10, 20};
    Person person{std::string("John"), 25};
    Person person2{"Jane", 30};  // Direct string literal

    // Compliant - array initialization with braces
    int arr[3]{1, 2, 3};

    // Generic code context where parentheses might be acceptable
    template<typename T>
    void genericFunction() {
        T obj(args...);  // May use parentheses in generic context
    }
}
